void setup() {
    // Wir legen eine Variable 'n' an und geben ihr den Wert 7.
    // Das System legt 'n' an einer freien Speicheradresse ab (hier: 0x08F2).
    int n = 7; 

    // Wir erstellen einen Zeiger 'p'.
    // Das '&'-Zeichen holt die Adresse von 'n' (also 0x08F2). 
    // Diese Adresse wird als Inhalt im Zeiger 'p' gespeichert.
    // (Der Zeiger 'p' selbst liegt auf einer eigenen Adresse, z.B. 0x08F4).
    int* p = &n; 

    // Wenn wir jetzt den Wert ändern wollen, auf den 'p' zeigt, 
    // nutzen wir den Stern (*). Folgender Befehl ändert den Inhalt 
    // an der Adresse 0x08F2 von 7 auf 10:
    // *p = 10; 
}
